import subprocess

def generate_requirements_txt_with_hashes():
    """
    Generates a requirements.txt file with hashes using pip.
    """
    try:
        subprocess.run(["pip", "compile", "--output-file=requirements.txt"], check=True)
        print("requirements.txt generated successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Failed to generate requirements.txt: {e}")

def update_requirements_txt_with_hashes():
    """
    Updates the existing requirements.txt file with latest hashes.
    """
    try:
        subprocess.run(["pip-compile", "--upgrade"], check=True)
        print("requirements.txt updated successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Failed to update requirements.txt: {e}")

def generate_poetry_lock():
    """
    Generates or updates the poetry.lock file using Poetry.
    """
    try:
        subprocess.run(["poetry", "lock"], check=True)
        print("poetry.lock generated/updated successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Failed to generate/update poetry.lock: {e}")

